BEGIN; CREATE TABLE IF NOT EXISTS public.shipment_cancellation_audit(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),shipment_id uuid NOT NULL REFERENCES public.shipment_logs(id),shipment_no_snapshot text NOT NULL,shipment_date date NOT NULL,reason text NOT NULL CHECK(char_length(btrim(reason)) BETWEEN 3 AND 500),cancelled_by uuid NOT NULL REFERENCES auth.users(id),cancelled_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX IF NOT EXISTS idx_shipment_cancellation_audit_shipment_time ON public.shipment_cancellation_audit(shipment_id,cancelled_at DESC); ALTER TABLE public.shipment_cancellation_audit ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS shipment_cancellation_audit_select ON public.shipment_cancellation_audit; CREATE POLICY shipment_cancellation_audit_select ON public.shipment_cancellation_audit FOR SELECT TO authenticated USING(public.is_manager()); REVOKE ALL ON TABLE public.shipment_cancellation_audit FROM PUBLIC,anon,authenticated; GRANT SELECT ON TABLE public.shipment_cancellation_audit TO authenticated; DO $$ BEGIN IF to_regprocedure('public.undo_shipment_core_20260722(uuid)') IS NULL THEN IF to_regprocedure('public.undo_shipment(uuid)') IS NULL THEN RAISE EXCEPTION 'Thieu RPC undo_shipment.'; END IF; ALTER FUNCTION public.undo_shipment(uuid) RENAME TO undo_shipment_core_20260722; END IF; IF to_regprocedure('public.undo_shipments_v1_core_20260722(uuid[])') IS NULL THEN IF to_regprocedure('public.undo_shipments_v1(uuid[])') IS NULL THEN RAISE EXCEPTION 'Thieu RPC undo_shipments_v1.'; END IF; ALTER FUNCTION public.undo_shipments_v1(uuid[]) RENAME TO undo_shipments_v1_core_20260722; END IF; END $$; CREATE OR REPLACE FUNCTION public.undo_shipment(p_shipment_id uuid) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path=public,pg_temp AS $$ BEGIN IF current_setting('app.allow_mistaken_shipment_cancel',true) IS DISTINCT FROM 'on' THEN RAISE EXCEPTION 'Hay dung chuc nang Huy phieu tao nham tren Nhat ky giao hang.' USING ERRCODE='42501'; END IF; RETURN public.undo_shipment_core_20260722(p_shipment_id); END $$; CREATE OR REPLACE FUNCTION public.undo_shipments_v1(p_shipment_ids uuid[]) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path=public,pg_temp AS $$ BEGIN IF current_setting('app.allow_mistaken_shipment_cancel',true) IS DISTINCT FROM 'on' THEN RAISE EXCEPTION 'Hay dung chuc nang Huy phieu tao nham tren Nhat ky giao hang.' USING ERRCODE='42501'; END IF; RETURN public.undo_shipments_v1_core_20260722(p_shipment_ids); END $$; CREATE OR REPLACE FUNCTION public.cancel_mistaken_shipments_v1(p_shipment_ids uuid[],p_reason text) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path=public,pg_temp AS $$ DECLARE v_user_id uuid:=auth.uid(); v_now timestamptz:=now(); v_today date:=(now() AT TIME ZONE 'Asia/Ho_Chi_Minh')::date; v_reason text:=btrim(COALESCE(p_reason,'')); v_ids uuid[]; v_requested_count integer; v_locked_count integer; v_tx_count integer:=0; v_plan record; v_product record; v_actual_qty numeric; BEGIN IF v_user_id IS NULL OR NOT public.is_admin() THEN RAISE EXCEPTION 'Chi Admin moi duoc huy phieu tao nham.' USING ERRCODE='42501'; END IF; IF char_length(v_reason)<3 OR char_length(v_reason)>500 THEN RAISE EXCEPTION 'Ly do huy phai tu 3 den 500 ky tu.'; END IF; IF p_shipment_ids IS NULL OR cardinality(p_shipment_ids)=0 OR array_position(p_shipment_ids,NULL) IS NOT NULL THEN RAISE EXCEPTION 'Danh sach phieu can huy khong hop le.'; END IF; SELECT array_agg(x.id ORDER BY x.id),count(*) INTO v_ids,v_requested_count FROM(SELECT DISTINCT unnest(p_shipment_ids) id)x; IF v_requested_count<>cardinality(p_shipment_ids) THEN RAISE EXCEPTION 'Danh sach phieu bi trung lap.'; END IF; IF v_requested_count>100 THEN RAISE EXCEPTION 'Moi lan chi duoc huy toi da 100 phieu.'; END IF; PERFORM 1 FROM public.shipment_logs s WHERE s.id=ANY(v_ids) AND s.deleted_at IS NULL ORDER BY s.id FOR UPDATE; GET DIAGNOSTICS v_locked_count=ROW_COUNT; IF v_locked_count<>v_requested_count THEN RAISE EXCEPTION 'Co phieu khong ton tai hoac da bi huy. Khong phieu nao thay doi.'; END IF; IF EXISTS(SELECT 1 FROM public.shipment_logs s WHERE s.id=ANY(v_ids) AND s.deleted_at IS NULL AND s.shipment_date<>v_today) THEN RAISE EXCEPTION 'Chi duoc huy va tao lai phieu trong dung ngay xuat. Phieu ngay cu phai dung Dieu chinh hang.'; END IF; CREATE TEMP TABLE mistaken_cancel_bases ON COMMIT DROP AS SELECT t.id,t.delivery_plan_id,t.product_id,t.tx_date::date tx_date FROM public.inventory_transactions t WHERE t.shipment_id=ANY(v_ids) AND t.adjusted_from_transaction_id IS NULL AND t.deleted_at IS NULL; IF NOT EXISTS(SELECT 1 FROM pg_temp.mistaken_cancel_bases) THEN RAISE EXCEPTION 'Phieu khong con giao dich xuat kho hop le.'; END IF; IF EXISTS(SELECT 1 FROM pg_temp.mistaken_cancel_bases WHERE delivery_plan_id IS NULL) THEN RAISE EXCEPTION 'Phieu co dong xuat kho khong gan ke hoach. Can kiem tra truoc khi huy.'; END IF; PERFORM 1 FROM public.inventory_transactions t WHERE (t.id IN(SELECT id FROM pg_temp.mistaken_cancel_bases) OR t.adjusted_from_transaction_id IN(SELECT id FROM pg_temp.mistaken_cancel_bases)) AND t.deleted_at IS NULL ORDER BY t.id FOR UPDATE; CREATE TEMP TABLE mistaken_cancel_plans ON COMMIT DROP AS SELECT DISTINCT delivery_plan_id id FROM pg_temp.mistaken_cancel_bases; PERFORM 1 FROM public.delivery_plans p WHERE p.id IN(SELECT id FROM pg_temp.mistaken_cancel_plans) AND p.deleted_at IS NULL ORDER BY p.id FOR UPDATE; FOR v_product IN SELECT product_id,min(tx_date) tx_date FROM pg_temp.mistaken_cancel_bases GROUP BY product_id ORDER BY product_id LOOP PERFORM public.inventory_lock_product(v_product.product_id); END LOOP; INSERT INTO public.shipment_cancellation_audit(shipment_id,shipment_no_snapshot,shipment_date,reason,cancelled_by,cancelled_at) SELECT s.id,s.shipment_no,s.shipment_date,v_reason,v_user_id,v_now FROM public.shipment_logs s WHERE s.id=ANY(v_ids) AND s.deleted_at IS NULL ORDER BY s.id; PERFORM set_config('app.skip_delivery_backlog_sync','on',true); PERFORM set_config('app.inventory_batch_replace','on',true); UPDATE public.inventory_transactions t SET deleted_at=v_now,deleted_by=v_user_id,updated_at=v_now,updated_by=v_user_id,note=COALESCE(t.note,'')||' | Huy phieu tao nham: '||v_reason WHERE (t.id IN(SELECT id FROM pg_temp.mistaken_cancel_bases) OR t.adjusted_from_transaction_id IN(SELECT id FROM pg_temp.mistaken_cancel_bases)) AND t.deleted_at IS NULL; GET DIAGNOSTICS v_tx_count=ROW_COUNT; FOR v_plan IN SELECT p.* FROM public.delivery_plans p JOIN pg_temp.mistaken_cancel_plans a ON a.id=p.id WHERE p.deleted_at IS NULL ORDER BY p.id LOOP SELECT COALESCE(sum(x.effective_qty),0) INTO v_actual_qty FROM(SELECT b.qty+COALESCE(sum(CASE WHEN adj.tx_type='adjust_in' THEN adj.qty WHEN adj.tx_type='adjust_out' THEN -adj.qty ELSE 0 END),0) effective_qty FROM public.inventory_transactions b LEFT JOIN public.inventory_transactions adj ON adj.adjusted_from_transaction_id=b.id AND adj.deleted_at IS NULL AND adj.tx_type IN('adjust_in','adjust_out') WHERE b.delivery_plan_id=v_plan.id AND b.tx_type='out' AND b.adjusted_from_transaction_id IS NULL AND b.deleted_at IS NULL GROUP BY b.id,b.qty)x; UPDATE public.delivery_plans SET actual_qty=COALESCE(v_actual_qty,0),is_completed=false,updated_at=v_now,updated_by=v_user_id WHERE id=v_plan.id; END LOOP; UPDATE public.shipment_logs SET deleted_at=v_now,note=COALESCE(note,'')||' | Huy phieu tao nham: '||v_reason WHERE id=ANY(v_ids) AND deleted_at IS NULL; PERFORM set_config('app.inventory_batch_replace','off',true); FOR v_product IN SELECT product_id,min(tx_date) tx_date FROM pg_temp.mistaken_cancel_bases GROUP BY product_id ORDER BY product_id LOOP PERFORM public.inventory_assert_no_negative_product_after(v_product.product_id,v_product.tx_date); END LOOP; PERFORM set_config('app.skip_delivery_backlog_sync','off',true); FOR v_plan IN SELECT id FROM pg_temp.mistaken_cancel_plans ORDER BY id LOOP PERFORM public.sync_delivery_backlog(v_plan.id); END LOOP; RETURN jsonb_build_object('success',true,'shipment_count',v_requested_count,'soft_deleted_tx_count',v_tx_count,'reason',v_reason,'message','Da huy phieu tao nham trong ngay. Lich su van duoc giu lai.'); EXCEPTION WHEN OTHERS THEN PERFORM set_config('app.inventory_batch_replace','off',true); PERFORM set_config('app.skip_delivery_backlog_sync','off',true); RAISE; END $$; REVOKE ALL ON FUNCTION public.undo_shipment_core_20260722(uuid) FROM PUBLIC,anon,authenticated; REVOKE ALL ON FUNCTION public.undo_shipments_v1_core_20260722(uuid[]) FROM PUBLIC,anon,authenticated; REVOKE ALL ON FUNCTION public.undo_shipment(uuid) FROM PUBLIC,anon,authenticated; REVOKE ALL ON FUNCTION public.undo_shipments_v1(uuid[]) FROM PUBLIC,anon,authenticated; REVOKE ALL ON FUNCTION public.cancel_mistaken_shipments_v1(uuid[],text) FROM PUBLIC,anon,authenticated; GRANT EXECUTE ON FUNCTION public.undo_shipment(uuid) TO authenticated; GRANT EXECUTE ON FUNCTION public.undo_shipments_v1(uuid[]) TO authenticated; GRANT EXECUTE ON FUNCTION public.cancel_mistaken_shipments_v1(uuid[],text) TO authenticated; NOTIFY pgrst,'reload schema'; COMMIT;
